import{_ as e,o as a,c as r,a as i}from"./app.7f9bd173.js";const u=JSON.parse('{"title":"第二期《构图》","description":"","frontmatter":{},"headers":[{"level":2,"title":"九条万能好用的法则","slug":"九条万能好用的法则","link":"#九条万能好用的法则","children":[]},{"level":2,"title":"1.黄金分割法","slug":"_1-黄金分割法","link":"#_1-黄金分割法","children":[]},{"level":2,"title":"2.点构图","slug":"_2-点构图","link":"#_2-点构图","children":[]},{"level":2,"title":"3.对角线构图","slug":"_3-对角线构图","link":"#_3-对角线构图","children":[]},{"level":2,"title":"4.中心构图","slug":"_4-中心构图","link":"#_4-中心构图","children":[]},{"level":2,"title":"5.三角形构图","slug":"_5-三角形构图","link":"#_5-三角形构图","children":[]},{"level":2,"title":"6.引导线构图","slug":"_6-引导线构图","link":"#_6-引导线构图","children":[]},{"level":2,"title":"7.重复线条构图","slug":"_7-重复线条构图","link":"#_7-重复线条构图","children":[]},{"level":2,"title":"8.开放式构图","slug":"_8-开放式构图","link":"#_8-开放式构图","children":[]},{"level":2,"title":"9.前景虚化构图","slug":"_9-前景虚化构图","link":"#_9-前景虚化构图","children":[]}],"relativePath":"PhotoTips/2.md"}'),h={name:"PhotoTips/2.md"},l=i('<h1 id="第二期《构图》" tabindex="-1">第二期《构图》 <a class="header-anchor" href="#第二期《构图》" aria-hidden="true">#</a></h1><h2 id="九条万能好用的法则" tabindex="-1">九条万能好用的法则 <a class="header-anchor" href="#九条万能好用的法则" aria-hidden="true">#</a></h2><h2 id="_1-黄金分割法" tabindex="-1">1.黄金分割法 <a class="header-anchor" href="#_1-黄金分割法" aria-hidden="true">#</a></h2><p>也就是三分法 九宫格 四个交叉点就是黄金分割点 拍人像是稳妥的构图</p><h2 id="_2-点构图" tabindex="-1">2.点构图 <a class="header-anchor" href="#_2-点构图" aria-hidden="true">#</a></h2><p>适合环境人像 场景通常视野开阔 画面干净 没有太多杂物 强调环境和人物和谐统一<br> 通常大环境 小人物<br> 人物只有一个点 有可能不好找到人物 所以也被称为构图</p><h2 id="_3-对角线构图" tabindex="-1">3.对角线构图 <a class="header-anchor" href="#_3-对角线构图" aria-hidden="true">#</a></h2><p>适用于拍摄景物或者风光<br> 拍摄植物和花朵 百试不爽 画面更饱满<br> 仔细寻找大自然本身就有的对角线哦</p><h2 id="_4-中心构图" tabindex="-1">4.中心构图 <a class="header-anchor" href="#_4-中心构图" aria-hidden="true">#</a></h2><p>并不是所有人像用三分法都好看<br> 有倒影的时候 一片平平 中间有突出的树的时候就适合中心构图 追求中心对称<br> 适用于任务特写 突出神态 饱满构图<br> 中心构图突出画面中心</p><h2 id="_5-三角形构图" tabindex="-1">5.三角形构图 <a class="header-anchor" href="#_5-三角形构图" aria-hidden="true">#</a></h2><p>静物和人像都可以尝试<br> 看起来饱满<br> 景物可以摆拍<br> 利用人物肢体动作 拍摄三角形构图<br> 看起来稳定又不失活泼</p><h2 id="_6-引导线构图" tabindex="-1">6.引导线构图 <a class="header-anchor" href="#_6-引导线构图" aria-hidden="true">#</a></h2><p>公路场景中 道路可以作为引导线</p><h2 id="_7-重复线条构图" tabindex="-1">7.重复线条构图 <a class="header-anchor" href="#_7-重复线条构图" aria-hidden="true">#</a></h2><p>利用画面本身的线条 如柱子 树木<br> 照片看起来工整 有秩序</p><h2 id="_8-开放式构图" tabindex="-1">8.开放式构图 <a class="header-anchor" href="#_8-开放式构图" aria-hidden="true">#</a></h2><p>先说什么是封闭式构图呢？<br> 它讲究画面完整 主体在画面中构图工整 框架内部布局均衡严谨完整<br> 开放式构图 主体不一定在画中心 注重主体与画外的联系 在意画面周围留下被切割不完整的形象 引导观众突破画面限制 产生空间联想<br> 并不是每张照片都追求构图工整 主体完整<br> 特写之类可以拍局部<br> 美食可以只拍部分 引导观众思考</p><h2 id="_9-前景虚化构图" tabindex="-1">9.前景虚化构图 <a class="header-anchor" href="#_9-前景虚化构图" aria-hidden="true">#</a></h2><p>利用镜头前花花草草 来大光圈虚化<br> 透光的布也可以 制造出神秘的画面</p>',20),d=[l];function t(n,_,s,c,o,p){return a(),r("div",null,d)}const f=e(h,[["render",t]]);export{u as __pageData,f as default};
